        case b.ch <- e:
        default:
            return fmt.Errorf("イベントバスのバッファが満杯です")
        }
    }
    return nil
}

func (b *ChannelBus) Subscribe(eventType string, handler event.Handler) error {
    b.mu.Lock()
    defer b.mu.Unlock()
    b.handlers[eventType] = append(b.handlers[eventType], handler)
    return nil
}

func (b *ChannelBus) dispatch() {
    defer b.wg.Done()
    for {
        select {
        case e := <-b.ch:
            b.runHandlers(e)
        case <-b.done:
            // 残存イベントをドレインしてから終了
            for len(b.ch) > 0 {
                b.runHandlers(<-b.ch)
            }
            return
        }
    }
}

func (b *ChannelBus) runHandlers(e event.Event) {
    b.mu.RLock()
